import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import Auth from './Auth';
import './App.css';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const LANGS = [
  { code:'en', speech:'en-US', flag:'🇬🇧', name:'English' },
  { code:'ta', speech:'ta-IN', flag:'🇮🇳', name:'Tamil' },
  { code:'hi', speech:'hi-IN', flag:'🇮🇳', name:'Hindi' },
  { code:'te', speech:'te-IN', flag:'🇮🇳', name:'Telugu' },
  { code:'ml', speech:'ml-IN', flag:'🇮🇳', name:'Malayalam' },
  { code:'kn', speech:'kn-IN', flag:'🇮🇳', name:'Kannada' },
  { code:'es', speech:'es-ES', flag:'🇪🇸', name:'Spanish' },
  { code:'fr', speech:'fr-FR', flag:'🇫🇷', name:'French' },
  { code:'de', speech:'de-DE', flag:'🇩🇪', name:'German' },
  { code:'zh', speech:'zh-CN', flag:'🇨🇳', name:'Chinese' },
  { code:'ar', speech:'ar-SA', flag:'🇸🇦', name:'Arabic' },
  { code:'ja', speech:'ja-JP', flag:'🇯🇵', name:'Japanese' },
  { code:'pt', speech:'pt-BR', flag:'🇧🇷', name:'Portuguese' },
  { code:'ru', speech:'ru-RU', flag:'🇷🇺', name:'Russian' },
  { code:'ko', speech:'ko-KR', flag:'🇰🇷', name:'Korean' },
  { code:'it', speech:'it-IT', flag:'🇮🇹', name:'Italian' },
];

const CATS = ['General','Math','Science','History','Literature','Programming','Languages','Other'];

// ═══ HELPERS ════════════════════════════════════════════════════

// Strip markdown markers for clean speech
const cleanForSpeech = (text='') =>
  text.replace(/^# /gm,'').replace(/^## /gm,'').replace(/^• /gm,'').replace(/\n+/g,' ').trim();

// Extract only bullet point content (for reading translations without headings)
const extractBulletContent = (text='') => {
  return text
    .split('\n')
    .filter(line => line.startsWith('• '))
    .map(line => line.slice(2))
    .join('. ')
    .trim();
};

// Find best voice, with fallback
const findVoice = (langCode) => {
  const voices = window.speechSynthesis.getVoices();
  const lang = LANGS.find(l => l.code === langCode);
  const speechCode = lang?.speech || 'en-US';
  return (
    voices.find(v => v.lang === speechCode) ||
    voices.find(v => v.lang.startsWith(langCode)) ||
    voices.find(v => v.lang.startsWith('en')) ||
    voices[0] || null
  );
};

// Actually speak — with fallback to backend TTS proxy for unsupported languages
const doSpeak = (text, langCode='en', onStart, onEnd, onError) => {
  if (!text?.trim()) return;
  window.speechSynthesis.cancel();

  const voice = findVoice(langCode);
  const lang  = LANGS.find(l => l.code === langCode);
  const speechCode = lang?.speech || 'en-US';

  // Check if we have a native voice for this language
  const hasNativeVoice = voice && voice.lang.startsWith(langCode);

  // For Indian languages without native voices, use backend TTS proxy
  if (!hasNativeVoice && ['ta', 'hi', 'te', 'ml', 'kn'].includes(langCode)) {
    console.log(`No native ${lang?.name} voice - using TTS service`);
    onStart?.();

    // Use backend proxy to avoid CORS
    const cleanText = cleanForSpeech(text).substring(0, 200);
    const audioUrl = `${API}/tts?text=${encodeURIComponent(cleanText)}&lang=${langCode}`;

    const audio = new Audio(audioUrl);
    audio.onended = () => onEnd?.();
    audio.onerror = (e) => {
      console.warn('TTS service failed, falling back to English:', e);
      // Fallback to English
      const utterEn = new SpeechSynthesisUtterance(cleanForSpeech(text));
      utterEn.lang = 'en-US';
      utterEn.onstart = () => onStart?.();
      utterEn.onend = () => onEnd?.();
      window.speechSynthesis.speak(utterEn);
    };
    audio.play().catch(e => {
      console.error('Audio play failed:', e);
      // Try English fallback
      const utterEn = new SpeechSynthesisUtterance(cleanForSpeech(text));
      utterEn.lang = 'en-US';
      utterEn.onend = () => onEnd?.();
      window.speechSynthesis.speak(utterEn);
    });
    return;
  }

  // Use native speech synthesis
  const utter = new SpeechSynthesisUtterance(cleanForSpeech(text));
  utter.lang  = speechCode;
  if (voice) utter.voice = voice;
  utter.rate  = 0.92;
  utter.pitch = 1;
  utter.onstart = () => onStart?.();
  utter.onend   = () => onEnd?.();
  utter.onerror = (e) => { onEnd?.(); onError?.(e); };
  window.speechSynthesis.speak(utter);
};

// ═══ STRUCTURED TEXT RENDERER ══════════════════════════════════
function StructuredText({ text }) {
  if (!text) return null;
  return (
    <div className="structured">
      {text.split('\n').map((line, i) => {
        if (!line.trim()) return <div key={i} className="s-gap" />;
        if (line.startsWith('# '))  return <h2 key={i} className="s-h1">{line.slice(2)}</h2>;
        if (line.startsWith('## ')) return <h3 key={i} className="s-h2">{line.slice(3)}</h3>;
        if (line.startsWith('• '))  return (
          <div key={i} className="s-bullet">
            <span className="s-dot">▸</span>
            <span>{line.slice(2)}</span>
          </div>
        );
        return <p key={i} className="s-plain">{line}</p>;
      })}
    </div>
  );
}

// ═══ READ ALOUD BUTTON ═════════════════════════════════════════
// langCode: which language to read in. 'en' = always English (safe fallback)
function ReadBtn({ text, langCode='en', label='🔊 Read Aloud', className='' }) {
  const [active, setActive] = useState(false);
  const [usingFallback, setUsingFallback] = useState(false);

  const toggle = () => {
    if (active) {
      window.speechSynthesis.cancel();
      setActive(false);
      return;
    }

    // Check if we'll use Google TTS fallback
    const voice = findVoice(langCode);
    const hasNativeVoice = voice && voice.lang.startsWith(langCode);
    const isIndianLang = ['ta', 'hi', 'te', 'ml', 'kn'].includes(langCode);

    if (!hasNativeVoice && isIndianLang) {
      setUsingFallback(true);
    } else {
      setUsingFallback(false);
    }

    doSpeak(
      text, langCode,
      () => setActive(true),
      () => { setActive(false); setUsingFallback(false); },
      () => { setActive(false); setUsingFallback(false); }
    );
  };

  // Clean up on unmount
  useEffect(() => () => { if (active) window.speechSynthesis.cancel(); }, []);

  const lang = LANGS.find(l => l.code === langCode);

  return (
    <div className={`read-wrap ${className}`}>
      <button
        className={`read-btn ${active ? 'reading' : ''}`}
        onClick={toggle}
        disabled={!text?.trim()}
        title={usingFallback ? `Using Google Translate voice for ${lang?.name}` : ''}
      >
        {active ? '⏹ Stop' : label}
      </button>
      {usingFallback && (
        <span className="fallback-tip">
          ✓ Using Google Translate voice (Windows doesn't have {lang?.name} voice installed)
        </span>
      )}
    </div>
  );
}

// ═══ TRANSLATE PANEL ═══════════════════════════════════════════
function TranslatePanel({ sourceText, onAddToNote }) {
  const [from,   setFrom]   = useState('en');
  const [to,     setTo]     = useState('ta');
  const [result, setResult] = useState('');
  const [busy,   setBusy]   = useState(false);
  const [err,    setErr]    = useState('');
  const resultRef = useRef(null);

  const translate = async () => {
    const txt = (sourceText || '').trim();
    if (!txt) { setErr('Add some content first, then translate.'); return; }
    setBusy(true); setResult(''); setErr('');
    try {
      const res = await axios.post(`${API}/translate`, { text: txt, from, to });
      if (res.data?.structured) {
        setResult(res.data.structured);
        setTimeout(() => resultRef.current?.scrollIntoView({ behavior:'smooth', block:'nearest' }), 100);
      } else setErr('Translation returned empty. Check server.');
    } catch(e) {
      setErr(e.response?.data?.message || 'Translation failed — is your backend running?');
    }
    finally { setBusy(false); }
  };

  const swap = () => { const t = from; setFrom(to); setTo(t); setResult(''); setErr(''); };
  const toLang = LANGS.find(l => l.code === to);
  const fromLang = LANGS.find(l => l.code === from);

  return (
    <div className="tp">
      {/* Header row */}
      <div className="tp-bar">
        <span className="tp-icon">🌐</span>
        <span className="tp-title">Translate</span>
        <div className="tp-controls">
          <select className="tp-sel" value={from} onChange={e => { setFrom(e.target.value); setResult(''); }}>
            {LANGS.map(l => <option key={l.code} value={l.code}>{l.flag} {l.name}</option>)}
          </select>
          <button className="tp-swap" onClick={swap} title="Swap">⇄</button>
          <select className="tp-sel" value={to} onChange={e => { setTo(e.target.value); setResult(''); }}>
            {LANGS.map(l => <option key={l.code} value={l.code}>{l.flag} {l.name}</option>)}
          </select>
          <button className="tp-go" onClick={translate} disabled={busy || !sourceText?.trim()}>
            {busy ? <><span className="spinner" />Translating…</> : `Translate →`}
          </button>
        </div>
      </div>

      {err && <p className="tp-err">⚠️ {err}</p>}

      {result && (
        <div className="tp-result" ref={resultRef}>
          {/* Result header */}
          <div className="tp-result-bar">
            <span className="tp-result-title">{toLang?.flag} {toLang?.name} — Translation</span>
            <div className="tp-result-btns">
              {/* Read in target language - only bullet content */}
              <ReadBtn text={extractBulletContent(result)} langCode={to} label={`🔊 Read (${toLang?.name})`} />
              {/* Always available: read in English */}
              {to !== 'en' && <ReadBtn text={extractBulletContent(result)} langCode="en" label="🔊 Read (English)" />}
              <button onClick={() => navigator.clipboard.writeText(cleanForSpeech(result))}>📋 Copy</button>
              {onAddToNote && <button onClick={() => onAddToNote(result)}>➕ Add to Note</button>}
            </div>
          </div>
          <StructuredText text={result} />
        </div>
      )}
    </div>
  );
}

// ═══ MAIN APP ═══════════════════════════════════════════════════
export default function App() {
  // Auth
  const [isAuth, setIsAuth]   = useState(false);
  const [user,   setUser]     = useState(null);
  // Notes
  const [notes,     setNotes]     = useState([]);
  const [note,      setNote]      = useState({ title:'', content:'', category:'General', source:'text' });
  const [editId,    setEditId]    = useState(null);
  const [filterCat, setFilterCat] = useState('All');
  const [search,    setSearch]    = useState('');
  const [loading,   setLoading]   = useState(false);
  // UI
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [tab,         setTab]         = useState('text');
  const [flash,       setFlash]       = useState({ type:'', text:'' });
  const [viewNote,    setViewNote]    = useState(null);
  // Voice
  const [listening,   setListening]   = useState(false);
  const [voiceLang,   setVoiceLang]   = useState('en-US');
  const [interim,     setInterim]     = useState('');
  const [audioFile,   setAudioFile]   = useState(null);    // voice file upload
  const [audioTranscript, setAudioTranscript] = useState('');
  const [transcribingAudio, setTranscribingAudio] = useState(false);
  // Video
  const [videoMode,      setVideoMode]      = useState('upload'); // 'upload' | 'screen'
  const [videoFile,      setVideoFile]      = useState(null);
  const [videoLang,      setVideoLang]      = useState('en-US');
  const [videoTranscript,setVideoTranscript]= useState('');
  const [transcribing,   setTranscribing]   = useState(false);
  const [videoStatus,    setVideoStatus]    = useState('');
  // Screen record + transcribe
  const [screenRec,      setScreenRec]      = useState(false);
  const [screenRecTranscript, setScreenRecTranscript] = useState('');
  const [screenRecChunks, setScreenRecChunks] = useState([]);
  // Screen
  const [recording,       setRecording]       = useState(false);
  const [screenLang,      setScreenLang]      = useState('en-US');
  const [screenTranscript,setScreenTranscript]= useState('');
  // Summary
  const [summary,    setSummary]    = useState('');
  const [genSummary, setGenSummary] = useState(false);
  // Chat
  const [chatOpen, setChatOpen] = useState(false);
  const [chatMsgs, setChatMsgs] = useState([]);
  const [chatIn,   setChatIn]   = useState('');
  const [thinking, setThinking] = useState(false);

  const voiceRef   = useRef(null);
  const videoRef   = useRef(null);
  const videoEl    = useRef(null);
  const audioEl    = useRef(null);
  const audioRef   = useRef(null);
  const cameraEl      = useRef(null);
  const liveRef       = useRef(null);
  const mediaRecRef   = useRef(null);
  const screenRecRef  = useRef(null);
  const chunksRef     = useRef([]);
  const screenRef  = useRef(null);
  const streamRef  = useRef(null);
  const chatEnd    = useRef(null);
  const summaryRef = useRef(null);

  // Preload voices
  useEffect(() => {
    const load = () => window.speechSynthesis.getVoices();
    load();
    window.speechSynthesis.onvoiceschanged = load;
  }, []);

  useEffect(() => {
    const u = localStorage.getItem('u');
    const t = localStorage.getItem('t');
    if (u && t) {
      setUser(JSON.parse(u)); setIsAuth(true);
      axios.defaults.headers.common['Authorization'] = `Bearer ${t}`;
    }
  }, []);

  useEffect(() => { if (isAuth) fetchNotes(); }, [isAuth, filterCat, search]);
  useEffect(() => { chatEnd.current?.scrollIntoView({ behavior:'smooth' }); }, [chatMsgs]);
  useEffect(() => { if (summary) setTimeout(() => summaryRef.current?.scrollIntoView({ behavior:'smooth', block:'start' }), 100); }, [summary]);
  useEffect(() => {
    if (!flash.text) return;
    const t = setTimeout(() => setFlash({ type:'', text:'' }), 4500);
    return () => clearTimeout(t);
  }, [flash]);
  useEffect(() => () => { window.speechSynthesis.cancel(); stopAll(); }, []);

  const notify = (type, text) => setFlash({ type, text });

  // ── SPEECH RECOGNITION ─────────────────────────────────────
  const buildRecog = (lang, onFinal, onEnd) => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { notify('error','Speech recognition requires Chrome or Edge.'); return null; }
    const r = new SR();
    r.lang = lang; r.continuous = true; r.interimResults = true;
    r.onresult = e => {
      let fin='', int='';
      for (let i = e.resultIndex; i < e.results.length; i++) {
        if (e.results[i].isFinal) fin += e.results[i][0].transcript + ' ';
        else int += e.results[i][0].transcript;
      }
      onFinal(fin, int);
    };
    r.onerror = e => { if (e.error !== 'no-speech') notify('error',`Speech error: ${e.error}`); };
    r.onend = onEnd || (() => {});
    return r;
  };

  const stopAll = () => {
    try { voiceRef.current?.stop(); } catch(e){}
    try { videoRef.current?.stop(); } catch(e){}
    try { screenRef.current?.stop(); } catch(e){}
    try { audioRef.current?.stop(); } catch(e){}
    streamRef.current?.getTracks().forEach(t => t.stop());
    if (videoEl.current) videoEl.current.pause();
    if (audioEl.current) { audioEl.current.pause(); audioEl.current.currentTime = 0; }
    setListening(false); setTranscribing(false); setTranscribingAudio(false); setRecording(false); setInterim('');
  };

  // Helper: get lang code from speech code
  const speechToCode = (speechCode) => LANGS.find(l => l.speech === speechCode)?.code || 'en';

  // ── AUTH ────────────────────────────────────────────────────
  const handleLogin = (u, token) => {
    setUser(u); setIsAuth(true);
    localStorage.setItem('u', JSON.stringify(u));
    localStorage.setItem('t', token);
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    notify('success', `Welcome, ${u.name}! 🎉`);
  };

  const handleLogout = () => {
    localStorage.clear();
    delete axios.defaults.headers.common['Authorization'];
    setUser(null); setIsAuth(false); setNotes([]); resetNote();
  };

  // ── NOTES CRUD ──────────────────────────────────────────────
  const fetchNotes = async () => {
    try {
      setLoading(true);
      const p = new URLSearchParams();
      if (filterCat !== 'All') p.append('category', filterCat);
      if (search) p.append('search', search);
      const res = await axios.get(`${API}/notes?${p}`);
      setNotes(res.data);
    } catch(e) {
      if (e.response?.status === 401) { handleLogout(); notify('error','Session expired.'); }
      else notify('error','Failed to load notes.');
    } finally { setLoading(false); }
  };

  const saveNote = async () => {
    if (!note.title || !note.content) { notify('error','Title and content are required.'); return; }
    try {
      editId
        ? await axios.put(`${API}/notes/${editId}`, note)
        : await axios.post(`${API}/notes`, note);
      notify('success', editId ? 'Note updated! ✅' : 'Note saved! ✅');
      resetNote(); fetchNotes();
    } catch(e) {
      if (e.response?.status === 401) { handleLogout(); notify('error','Session expired.'); }
      else notify('error','Save failed.');
    }
  };

  const deleteNote = async id => {
    if (!window.confirm('Delete this note?')) return;
    try { await axios.delete(`${API}/notes/${id}`); notify('success','Deleted.'); fetchNotes(); }
    catch { notify('error','Delete failed.'); }
  };

  const startEdit = n => {
    setNote({ title:n.title, content:n.content, category:n.category, source:n.source });
    setEditId(n._id); setSummary('');
    window.scrollTo({ top:0, behavior:'smooth' });
  };

  const resetNote = () => {
    setNote({ title:'', content:'', category:'General', source:'text' });
    setEditId(null); setSummary(''); setTab('text');
    setVideoFile(null); setVideoTranscript(''); setVideoStatus('');
    setScreenRecTranscript(''); setScreenRec(false); setVideoMode('upload');
    setScreenRecChunks([]); chunksRef.current = [];
    try { mediaRecRef.current?.stop(); } catch(e) {}
    try { screenRecRef.current?.getTracks().forEach(t=>t.stop()); } catch(e) {}
    setScreenTranscript(''); setInterim('');
    setAudioFile(null); setAudioTranscript('');
    stopAll();
  };

  const downloadNote = n => {
    const a = document.createElement('a');
    a.href = URL.createObjectURL(new Blob([n.content], { type:'text/plain' }));
    a.download = `${n.title}.txt`; a.click();
  };

  // ── SMART SUMMARY ───────────────────────────────────────────
  const doSummary = async () => {
    if (!note.content) { notify('error','Add content first.'); return; }
    setGenSummary(true); setSummary('');
    try {
      const res = await axios.post(`${API}/generate-summary`, { content: note.content });
      const s = res.data?.summary;
      if (s?.trim()) { setSummary(s); notify('success','Summary generated! Scroll down ↓'); }
      else notify('error','Summary was empty. Add more text and try again.');
    } catch(e) {
      notify('error', e.response?.data?.message || 'Summary failed.');
    }
    finally { setGenSummary(false); }
  };

  // ── VOICE TAB ──────────────────────────────────────────────
  // ── AUDIO FILE TRANSCRIPTION ────────────────────────────────
  // Uses backend transcription API (AssemblyAI)
  const transcribeAudioFile = async () => {
    if (!audioFile) { notify('error','Upload an audio file first.'); return; }
    setTranscribingAudio(true); setAudioTranscript('');
    notify('success','Uploading audio file to transcription service… please wait.');

    // Create cancel token
    const cancelTokenSource = axios.CancelToken.source();
    audioRef.current = { cancel: () => cancelTokenSource.cancel('User cancelled transcription') };

    try {
      const formData = new FormData();
      formData.append('file', audioFile);
      formData.append('language', speechToCode(voiceLang));

      const res = await axios.post(`${API}/transcribe`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 600000, // 10 minute timeout
        cancelToken: cancelTokenSource.token
      });

      if (res.data?.transcript) {
        const transcript = res.data.transcript;
        setAudioTranscript(transcript);
        setNote(p => ({...p, content: transcript}));
        notify('success', 'Audio transcription complete! ✅');
      } else {
        notify('error', 'No transcription returned.');
      }
    } catch(e) {
      if (axios.isCancel(e)) {
        notify('error', 'Transcription cancelled.');
      } else {
        const msg = e.response?.data?.message || e.message;
        notify('error', 'Transcription failed: ' + msg);
      }
    } finally {
      setTranscribingAudio(false);
      audioRef.current = null;
    }
  };

  // ── SCREEN RECORD + AUDIO EXTRACT + TRANSCRIBE ─────────────
  // Records screen WITH audio, saves the recording, then sends
  // the audio to AssemblyAI for accurate transcription
  const startScreenRecord = async () => {
    console.log('🖥️ Starting screen recording...');
    try {
      // Ask user to share screen WITH audio
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: { mediaSource: 'screen' },
        audio: true   // captures system audio (tab/app audio)
      });

      console.log('✅ Screen share granted');
      console.log('   Video tracks:', stream.getVideoTracks().length);
      console.log('   Audio tracks:', stream.getAudioTracks().length);

      screenRecRef.current = stream;
      chunksRef.current    = [];
      setScreenRecTranscript('');
      setVideoStatus('🔴 Recording screen… navigate to your page and speak/play audio');

      // MediaRecorder captures both video + audio
      const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')
        ? 'video/webm;codecs=vp9,opus'
        : MediaRecorder.isTypeSupported('video/webm')
        ? 'video/webm'
        : 'video/mp4';

      console.log('🎬 Using MIME type:', mimeType);

      const recorder = new MediaRecorder(stream, { mimeType });
      mediaRecRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data && e.data.size > 0) {
          chunksRef.current.push(e.data);
          console.log('📦 Chunk received:', (e.data.size / 1024).toFixed(1), 'KB, Total chunks:', chunksRef.current.length);
        }
      };

      recorder.onstop = async () => {
        console.log('⏹️ Recording stopped, processing...');
        console.log('   Total chunks:', chunksRef.current.length);

        // Stream ended — now process the recorded audio
        setScreenRec(false);
        setVideoStatus('⏳ Processing recording… extracting audio for transcription');
        stream.getTracks().forEach(t => t.stop());

        if (chunksRef.current.length === 0) {
          console.error('❌ No chunks recorded!');
          setVideoStatus('');
          notify('error', 'No data recorded. Try again.');
          return;
        }

        // Create a file blob from recorded chunks
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const file = new File([blob], 'screen-recording.webm', { type: mimeType });

        console.log('📁 Created file:', file.name, (blob.size / 1024 / 1024).toFixed(2), 'MB');
        notify('success', `Recording saved (${(blob.size / 1024 / 1024).toFixed(1)}MB) — sending for transcription…`);
        setVideoStatus('☁️ Uploading to transcription service…');

        // Send to backend for AssemblyAI transcription
        try {
          const formData = new FormData();
          formData.append('file', file);
          formData.append('language', speechToCode(videoLang));

          console.log('⬆️ Uploading to backend for transcription...');
          const res = await axios.post(`${API}/transcribe`, formData, {
            headers: { 'Content-Type': 'multipart/form-data' },
            timeout: 600000
          });

          console.log('✅ Transcription response received');
          console.log('   Transcript length:', res.data?.transcript?.length || 0);

          if (res.data?.transcript) {
            console.log('✅ Setting transcript:', res.data.transcript.substring(0, 100) + '...');
            setScreenRecTranscript(res.data.transcript);
            setNote(p => ({ ...p, content: res.data.transcript }));
            setVideoStatus('');
            notify('success', 'Screen recording transcribed! ✅');
          } else {
            console.warn('⚠️ No transcript in response');
            setVideoStatus('');
            notify('error', 'No transcript returned. Recording may have no speech.');
          }
        } catch(e) {
          console.error('❌ Transcription failed:', e);
          console.error('   Error message:', e.response?.data?.message || e.message);
          setVideoStatus('');
          notify('error', 'Transcription failed: ' + (e.response?.data?.message || e.message));
        }

        chunksRef.current = [];
      };

      // Collect data every second
      recorder.start(1000);
      setScreenRec(true);
      setNote(p => ({ ...p, source: 'screen' }));
      console.log('▶️ Recording started, collecting chunks every 1s');

      // Auto-stop when user stops sharing
      stream.getVideoTracks()[0].onended = () => {
        console.log('🛑 User stopped sharing screen');
        if (recorder.state !== 'inactive') recorder.stop();
      };

      notify('success', '🖥️ Screen recording started! Navigate anywhere — come back and click Stop when done.');

    } catch(e) {
      console.error('❌ Screen recording error:', e);
      if (e.name === 'NotAllowedError') notify('error', 'Screen sharing cancelled.');
      else notify('error', 'Screen record failed: ' + e.message);
      setScreenRec(false);
      setVideoStatus('');
    }
  };

  const stopScreenRecord = () => {
    console.log('🛑 Stop button clicked');
    if (mediaRecRef.current && mediaRecRef.current.state !== 'inactive') {
      console.log('   Stopping recorder...');
      mediaRecRef.current.stop(); // triggers onstop → transcription
    } else {
      console.warn('   Recorder not active or not found');
    }
    setVideoStatus('⏳ Finishing recording…');
  };

  // ── VIDEO TAB ──────────────────────────────────────────────
  const handleVideoUpload = e => {
    const f = e.target.files[0]; if (!f) return;
    setVideoFile(f); setVideoTranscript('');
    notify('success', `"${f.name}" loaded. Choose language then Transcribe.`);
  };

  const startVideoTranscribe = async () => {
    if (!videoFile) { notify('error','Upload a video first.'); return; }
    setTranscribing(true); setVideoTranscript(''); setVideoStatus('');
    notify('success','Uploading video to transcription service… this may take a few minutes.');
    setVideoStatus('⏳ Uploading video to server…');

    try {
      const formData = new FormData();
      formData.append('file', videoFile);
      formData.append('language', speechToCode(videoLang));

      setVideoStatus('☁️ Video uploaded — transcription in progress…');

      const res = await axios.post(`${API}/transcribe`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 600000 // 10 minute timeout for long videos
      });

      if (res.data?.transcript) {
        const transcript = res.data.transcript;
        setVideoTranscript(transcript);
        setNote(p => ({...p, content: transcript}));
        setVideoStatus('');
        notify('success', 'Video transcription complete! ✅');
      } else {
        setVideoStatus('');
        notify('error', 'No transcription returned.');
      }
    } catch(e) {
      const msg = e.response?.data?.message || e.message;
      setVideoStatus('');
      notify('error', 'Transcription failed: ' + msg);
    } finally {
      setTranscribing(false);
    }

    setNote(p => ({ ...p, source:'video' }));
  };

  // ── SCREEN TAB ─────────────────────────────────────────────
  const startScreen = async () => {
    stopAll();
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video:true, audio:true });
      streamRef.current = stream;
      let acc = '';
      const r = buildRecog(screenLang,
        fin => { if(fin){ acc += fin; setScreenTranscript(acc); setNote(p=>({...p,content:acc})); } },
        () => {}
      );
      if (r) { screenRef.current = r; r.start(); }
      stream.getVideoTracks()[0].onended = stopScreen;
      setRecording(true); setNote(p => ({ ...p, source:'screen' }));
      notify('success','Recording! Speak and words appear live below.');
    } catch(e) {
      if (e.name === 'NotAllowedError') notify('error','Screen sharing permission denied.');
      else notify('error','Recording failed: ' + e.message);
    }
  };

  const stopScreen = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    screenRef.current?.stop();
    setRecording(false);
    notify('success','Recording stopped. Transcript ready!');
  };

  // ── AI CHAT ────────────────────────────────────────────────
  const askAI = async () => {
    if (!chatIn.trim()) return;
    setChatMsgs(p => [...p, { role:'user', content:chatIn }]);
    const q = chatIn; setChatIn(''); setThinking(true);
    try {
      const res = await axios.post(`${API}/chat`, { question:q, allNotes:notes });
      setChatMsgs(p => [...p, { role:'assistant', content:res.data.response }]);
    } catch { notify('error','AI chat failed.'); }
    finally { setThinking(false); }
  };

  if (!isAuth) return <Auth onLogin={handleLogin} />;

  // ══════════════════════════════════════════════════════════════
  return (
    <div className="app">

      {/* ══ SIDEBAR ══════════════════════════════════════════ */}
      <aside className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sb-hd">
          {sidebarOpen && <span className="sb-brand">📚 SmartNotes</span>}
          <button className="sb-tog" onClick={() => setSidebarOpen(p=>!p)}>
            {sidebarOpen ? '◀' : '▶'}
          </button>
        </div>

        <div className="sb-user">
          <div className="sb-av">{user?.name?.[0]?.toUpperCase()}</div>
          <div className="sb-ui">
            <p className="sb-name">{user?.name}</p>
            <p className="sb-email">{user?.email}</p>
          </div>
          <button className="sb-out" onClick={handleLogout}>🚪</button>
        </div>

        <div className="sb-search">
          <span className="sb-si">🔍</span>
          <input placeholder="Search notes…" value={search} onChange={e=>setSearch(e.target.value)} />
        </div>

        <select className="sb-cat" value={filterCat} onChange={e=>setFilterCat(e.target.value)}>
          <option value="All">📂 All</option>
          {CATS.map(c => <option key={c}>{c}</option>)}
        </select>

        <button className="sb-new" onClick={resetNote}>＋ New Note</button>

        <div className="sb-list">
          {loading
            ? <div className="sb-load"><span className="spinner" /></div>
            : notes.length === 0
            ? <p className="sb-mt">No notes yet.<br />Create your first ☝️</p>
            : notes.map(n => (
              <div key={n._id} className={`nb ${editId===n._id?'nb-active':''}`}>
                <div className="nb-top">
                  <span className="nb-title">{n.title}</span>
                  <span className="nb-cat">{n.category}</span>
                </div>
                <p className="nb-preview">{n.content.slice(0,60)}…</p>
                <div className="nb-acts">
                  <button onClick={()=>startEdit(n)} className="na-e">✏️</button>
                  <button onClick={()=>setViewNote(n)} className="na-v">👁️</button>
                  <button onClick={()=>downloadNote(n)} className="na-d">⬇️</button>
                  <button onClick={()=>deleteNote(n._id)} className="na-x">🗑️</button>
                </div>
              </div>
            ))}
        </div>
      </aside>

      {/* ══ MAIN ════════════════════════════════════════════ */}
      <main className="main">

        {/* Page title */}
        <div className="ph">
          <h1 className="ph-title">✨ Smart Notes</h1>
          <p className="ph-sub">Capture in any language · Translate · Summarise · Read Aloud</p>
        </div>

        {/* Flash message */}
        {flash.text && (
          <div className={`flash flash-${flash.type}`}>
            <span>{flash.text}</span>
            <button onClick={()=>setFlash({type:'',text:''})}>✕</button>
          </div>
        )}

        {/* ── EDITOR CARD ─────────────────────────────────── */}
        <div className="card">

          {/* Card top row */}
          <div className="card-top">
            <h2 className="card-label">{editId ? '✏️ Edit Note' : '📝 New Note'}</h2>
            {editId && <button className="btn-x" onClick={resetNote}>✕ Cancel</button>}
          </div>

          {/* Title + Category */}
          <div className="fields">
            <input className="f-title" type="text" placeholder="Note title…"
              value={note.title} onChange={e=>setNote(p=>({...p,title:e.target.value}))} />
            <select className="f-cat" value={note.category} onChange={e=>setNote(p=>({...p,category:e.target.value}))}>
              {CATS.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>

          {/* ── Tab buttons ── */}
          <div className="tabs">
            {[['text','✍️','Text'],['voice','🎤','Voice'],['video','🎥','Video'],['screen','🖥️','Screen']].map(([id,ico,lbl])=>(
              <button key={id} className={`tab ${tab===id?'tab-on':''}`}
                onClick={()=>{ setTab(id); stopAll(); }}>
                <span>{ico}</span><span className="tl">{lbl}</span>
              </button>
            ))}
          </div>

          {/* ══ TEXT TAB ══════════════════════════════════ */}
          {tab==='text' && (
            <section className="tc">
              <textarea className="ta" rows={9} placeholder="Start typing your notes here…"
                value={note.content} onChange={e=>setNote(p=>({...p,content:e.target.value}))} />
              {/* Read Aloud: English only for typed text */}
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode="en" label="🔊 Read Aloud (English)" />
              </div>
              <TranslatePanel 
                sourceText={summary ? (note.content + '\n\n━━━ SMART SUMMARY ━━━\n\n' + summary) : note.content} 
                onAddToNote={t=>setNote(p=>({...p,content:p.content+'\n\n'+t}))} 
              />
            </section>
          )}

          {/* ══ VOICE TAB ═════════════════════════════════ */}
          {tab==='voice' && (
            <section className="tc">
              {/* ── Header Hint ── */}
              <div className="hint">
                📂 <strong>Upload Audio File</strong> for accurate cloud transcription<br/>
                Supports: MP3, WAV, M4A, OGG, FLAC (max 100MB)<br/>
                ✨ Powered by AssemblyAI for professional-grade transcription
              </div>

              {/* ── Audio File Upload Section ── */}
              <div className="section-box">
                <div className="section-title">🎵 Audio File Transcription</div>

                <label className="upload">
                  <input 
                    type="file" 
                    accept="audio/*,.mp3,.wav,.m4a,.ogg,.flac" 
                    onChange={e => {
                      const f = e.target.files[0];
                      if (f) {
                        setAudioFile(f);
                        setAudioTranscript('');
                        notify('success', `✅ "${f.name}" loaded. Click Transcribe to start.`);
                      }
                    }} 
                    hidden 
                  />
                  <span className="u-ico">🎵</span>
                  <span className="u-main">
                    {audioFile ? audioFile.name : 'Click to select audio file'}
                  </span>
                  <span className="u-sub">MP3 · WAV · M4A · OGG · FLAC · Up to 100MB</span>
                </label>

                {audioFile && (
                  <div className="ctrl" style={{marginTop: '1rem'}}>
                    {!transcribingAudio ? (
                      <button className="rbtn" onClick={transcribeAudioFile}>
                        ▶ Transcribe Audio File
                      </button>
                    ) : (
                      <button 
                        className="rbtn rbtn-on" 
                        onClick={() => {
                          if (audioRef.current?.cancel) audioRef.current.cancel();
                          setTranscribingAudio(false);
                          notify('info', 'Transcription cancelled');
                        }}
                      >
                        <span className="dot" /> Stop Transcription
                      </button>
                    )}
                    {transcribingAudio && <span className="live">🔴 Transcribing… Please wait</span>}
                  </div>
                )}
              </div>

              {/* ── Transcript Display ── */}
              {audioTranscript && (
                <div className="tbox">
                  <div className="tbox-head">📄 Transcription Result</div>
                  <div className="tbox-ctrl">
                    <ReadBtn text={audioTranscript} langCode="en" label="🔊 Read Aloud" />
                    <button 
                      className="rbtn"
                      onClick={() => {
                        setNote(p => ({...p, content: audioTranscript}));
                        notify('success', 'Transcript added to note!');
                      }}
                    >
                      ➕ Use as Note
                    </button>
                    <button 
                      className="rbtn"
                      style={{background: '#6B7280'}}
                      onClick={() => {
                        setAudioFile(null);
                        setAudioTranscript('');
                        notify('info', 'Cleared transcript');
                      }}
                    >
                      🗑️ Clear
                    </button>
                  </div>
                  <p className="tbox-text">{audioTranscript}</p>
                </div>
              )}

              {/* ── Translation Panel ── */}
              {audioTranscript && (
                <TranslatePanel 
                  sourceText={audioTranscript} 
                  onAddToNote={t => setNote(p => ({...p, content: p.content + '\n\n' + t}))} 
                />
              )}
            </section>
          )}

          {/* ══ VIDEO TAB ══════════════════════════════════ */}
          {tab==='video' && (
            <section className="tc">

              {/* ── Mode switcher ── */}
              <div className="mode-switch">
                <button
                  className={`mode-btn ${videoMode==='upload' ? 'mode-on' : ''}`}
                  onClick={() => { setVideoMode('upload'); }}>
                  📁 Upload Video
                </button>
                <button
                  className={`mode-btn ${videoMode==='screen' ? 'mode-on' : ''}`}
                  onClick={() => { setVideoMode('screen'); setVideoFile(null); }}>
                  🖥️ Record Screen
                </button>
              </div>

              {/* ══ UPLOAD MODE ══ */}
              {videoMode==='upload' && (
                <div className="section-box">
                  <div className="section-title">📁 Upload Video File</div>
                  <div className="hint">
                    Upload a recorded video → select spoken language → press <strong>Transcribe</strong> → 
                    file sent to cloud → accurate text returned in 2–5 minutes ✨
                  </div>

                  <label className="upload">
                    <input type="file" accept="video/*,audio/*" onChange={handleVideoUpload} hidden />
                    <span className="u-ico">📹</span>
                    <span className="u-main">{videoFile ? videoFile.name : 'Click to upload video or audio'}</span>
                    <span className="u-sub">MP4 · MOV · AVI · WebM · MP3 · WAV</span>
                  </label>

                  {videoFile && (
                    <>
                      {videoFile.type.startsWith('video') && (
                        <video ref={videoEl} className="vid" controls
                          src={URL.createObjectURL(videoFile)} />
                      )}
                      <div className="ctrl">
                        <div className="lg">
                          <label>Language spoken in video</label>
                          <select value={videoLang} onChange={e=>setVideoLang(e.target.value)}>
                            {LANGS.map(l=><option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                          </select>
                        </div>
                        {!transcribing
                          ? <button className="rbtn" onClick={startVideoTranscribe}>▶ Transcribe</button>
                          : <button className="rbtn rbtn-on" onClick={()=>setTranscribing(false)}>
                              <span className="dot" /> Stop
                            </button>}
                        {transcribing && <span className="live">🔴 Processing…</span>}
                      </div>
                      {videoStatus && <div className="vstatus">{videoStatus}</div>}
                      {videoTranscript && (
                        <div className="tbox">
                          <div className="tbox-hd">
                            <span>📝 Transcript</span>
                            <div className="tbox-acts">
                              <ReadBtn text={videoTranscript} langCode={speechToCode(videoLang)} label="🔊 Read" />
                              <ReadBtn text={videoTranscript} langCode="en" label="🔊 Read (English)" />
                              <button onClick={()=>setNote(p=>({...p,content:videoTranscript}))}>➕ Use as Note</button>
                            </div>
                          </div>
                          <p className="tbox-text">{videoTranscript}</p>
                        </div>
                      )}
                    </>
                  )}
                </div>
              )}

              {/* ══ SCREEN RECORD MODE ══ */}
              {videoMode==='screen' && (
                <div className="section-box">
                  <div className="section-title">🖥️ Record Screen + Transcribe Audio</div>
                  <div className="hint">
                    💡 <strong>How it works:</strong>
                    <ol style={{marginTop:'.4rem',paddingLeft:'1.25rem',lineHeight:2}}>
                      <li>Select the language spoken in the audio</li>
                      <li>Click <strong>Start Recording</strong></li>
                      <li>Pick the screen/tab/window to record</li>
                      <li>✅ <strong>Make sure to tick "Share tab audio"</strong> in the dialog</li>
                      <li>Navigate to your desired page — audio is captured automatically</li>
                      <li>Come back here and click <strong>Stop Recording</strong></li>
                      <li>Recording is sent to cloud → transcript appears!</li>
                    </ol>
                    <span className="warn">⚠️ Tick "Share audio" in Chrome's screen share dialog for audio capture!</span>
                  </div>

                  {/* Recording status */}
                  {screenRec && (
                    <div className="rec-status">
                      <span className="rec-dot-lg"></span>
                      Recording in progress — you can navigate away. Come back and click Stop when done.
                    </div>
                  )}

                  {videoStatus && <div className="vstatus">{videoStatus}</div>}

                  <div className="ctrl">
                    <div className="lg">
                      <label>Language spoken in recording</label>
                      <select value={videoLang} onChange={e=>setVideoLang(e.target.value)}
                        disabled={screenRec}>
                        {LANGS.map(l=><option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                      </select>
                    </div>
                    {!screenRec
                      ? <button className="rbtn" onClick={startScreenRecord}>🖥️ Start Recording</button>
                      : <button className="rbtn rbtn-on" onClick={stopScreenRecord}>
                          <span className="dot" /> Stop Recording
                        </button>}
                    {screenRec && <span className="live">🔴 Recording</span>}
                  </div>

                  {screenRecTranscript && (
                    <div className="tbox">
                      <div className="tbox-hd">
                        <span>📝 Transcript from Recording</span>
                        <div className="tbox-acts">
                          <ReadBtn text={screenRecTranscript} langCode={speechToCode(videoLang)} label="🔊 Read" />
                          <ReadBtn text={screenRecTranscript} langCode="en" label="🔊 Read (English)" />
                          <button onClick={()=>setNote(p=>({...p,content:screenRecTranscript}))}>➕ Use as Note</button>
                          <button onClick={()=>setScreenRecTranscript('')}>🗑️ Clear</button>
                        </div>
                      </div>
                      <p className="tbox-text">{screenRecTranscript}</p>
                    </div>
                  )}
                </div>
              )}

              {/* ── Textarea ── */}
              <textarea className="ta" rows={6}
                placeholder="Transcript appears here automatically…"
                value={note.content}
                onChange={e=>setNote(p=>({...p,content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode={speechToCode(videoLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===videoLang)?.name})`} />
                <ReadBtn text={note.content} langCode="en" label="🔊 Read (English)" />
              </div>
              <TranslatePanel
                sourceText={note.content || videoTranscript || screenRecTranscript}
                onAddToNote={t=>setNote(p=>({...p,content:p.content+'\n\n'+t}))} />
            </section>
          )}
          {/* ══ SCREEN TAB ═════════════════════════════════ */}
          {tab==='screen' && (
            <section className="tc">
              <div className="hint">
                💡 Pick language → <strong>Start Recording</strong> → share screen → speak → live transcript appears
                <br /><span className="warn">⚠️ Only spoken audio is captured (not text visible on screen).</span>
              </div>

              <div className="ctrl">
                <div className="lg">
                  <label>Spoken language</label>
                  <select value={screenLang} onChange={e=>setScreenLang(e.target.value)}>
                    {LANGS.map(l=><option key={l.speech} value={l.speech}>{l.flag} {l.name}</option>)}
                  </select>
                </div>
                {!recording
                  ? <button className="rbtn" onClick={startScreen}>🖥️ Start Recording</button>
                  : <button className="rbtn rbtn-on" onClick={stopScreen}><span className="dot" /> Stop</button>}
                {recording && <span className="live">🔴 LIVE</span>}
              </div>

              {screenTranscript && (
                <div className="tbox">
                  <div className="tbox-hd">
                    <span>📝 Live Transcript</span>
                    <div className="tbox-acts">
                      <ReadBtn text={screenTranscript} langCode={speechToCode(screenLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===screenLang)?.name})`} />
                      <ReadBtn text={screenTranscript} langCode="en" label="🔊 Read (English)" />
                      <button onClick={()=>setNote(p=>({...p,content:screenTranscript}))}>➕ Use</button>
                      <button onClick={()=>setScreenTranscript('')}>🗑️</button>
                    </div>
                  </div>
                  <p className="tbox-text">{screenTranscript}</p>
                </div>
              )}

              <textarea className="ta" rows={8} placeholder="Live transcript appears here…"
                value={note.content} onChange={e=>setNote(p=>({...p,content:e.target.value}))} />
              <div className="ta-actions">
                <ReadBtn text={note.content} langCode={speechToCode(screenLang)} label={`🔊 Read (${LANGS.find(l=>l.speech===screenLang)?.name})`} />
                <ReadBtn text={note.content} langCode="en" label="🔊 Read (English)" />
              </div>
              <TranslatePanel sourceText={note.content||screenTranscript} onAddToNote={t=>setNote(p=>({...p,content:p.content+'\n\n'+t}))} />
            </section>
          )}

          {/* ── Save / Summary row ── */}
          <div className="bot-bar">
            <button className="ab" onClick={doSummary} disabled={!note.content||genSummary}>
              {genSummary ? <><span className="spinner"/>Generating…</> : '✨ Smart Summary'}
            </button>
            <button className="ab ab-save" onClick={saveNote}>
              💾 {editId ? 'Update' : 'Save Note'}
            </button>
          </div>

          {/* ══ SUMMARY PANEL ══════════════════════════════ */}
          {summary && (
            <div className="result-panel" ref={summaryRef}>
              <div className="rp-hd">
                <div className="rp-hd-left">
                  <span className="rp-ico">✨</span>
                  <h3>Smart Summary</h3>
                </div>
                <div className="rp-hd-right">
                  <ReadBtn text={summary} langCode="en" label="🔊 Read (English)" className="rp-read" />
                  <button onClick={()=>setNote(p=>({...p,content:summary}))}>➕ Use as Note</button>
                  <button onClick={()=>navigator.clipboard.writeText(cleanForSpeech(summary))}>📋 Copy</button>
                  <button className="rp-close" onClick={()=>setSummary('')}>✕</button>
                </div>
              </div>
              <StructuredText text={summary} />
              {/* Translate the summary too */}
              <div className="rp-translate">
                <TranslatePanel
                  sourceText={summary}
                  onAddToNote={t=>setNote(p=>({...p,content:p.content+'\n\n'+t}))}
                />
              </div>
            </div>
          )}
        </div>

        {/* Chat FAB */}
        <button className="cfab" onClick={()=>setChatOpen(p=>!p)}>💬</button>

        {/* Chat panel */}
        {chatOpen && (
          <div className="cpanel">
            <div className="cp-hd">
              <span>🤖 AI Assistant</span>
              <button onClick={()=>setChatOpen(false)}>✕</button>
            </div>
            <div className="cp-body">
              {chatMsgs.length === 0
                ? <div className="cp-empty">
                    <p>👋 Ask me about your notes!</p>
                    {['How many notes?','What categories?','Summarize notes'].map(s=>(
                      <button key={s} className="cp-sug" onClick={()=>setChatIn(s)}>{s}</button>
                    ))}
                  </div>
                : chatMsgs.map((m,i)=>(
                    <div key={i} className={`cm ${m.role}`}>
                      <div className="cb">{m.content}</div>
                    </div>
                  ))}
              {thinking && <div className="cm assistant"><div className="cb"><div className="dots"><span/><span/><span/></div></div></div>}
              <div ref={chatEnd}/>
            </div>
            <div className="cp-ft">
              <input placeholder="Ask…" value={chatIn}
                onChange={e=>setChatIn(e.target.value)} onKeyPress={e=>e.key==='Enter'&&askAI()} />
              <button onClick={askAI} disabled={!chatIn.trim()}>➤</button>
            </div>
          </div>
        )}
      </main>

      {/* ══ VIEW NOTE MODAL ════════════════════════════════ */}
      {viewNote && (
        <div className="overlay" onClick={()=>setViewNote(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-hd">
              <div>
                <h2>{viewNote.title}</h2>
                <div className="modal-tags">
                  <span className="tag">{viewNote.category}</span>
                  <span className="tag t2">{viewNote.source}</span>
                </div>
              </div>
              <button onClick={()=>setViewNote(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="modal-text">{viewNote.content}</div>
              <div className="modal-acts">
                <ReadBtn text={viewNote.content} langCode="en" label="🔊 Read (English)" />
                <button onClick={()=>downloadNote(viewNote)}>⬇️ Download</button>
                <button onClick={()=>{startEdit(viewNote);setViewNote(null);}}>✏️ Edit</button>
                <button className="del" onClick={()=>{deleteNote(viewNote._id);setViewNote(null);}}>🗑️ Delete</button>
              </div>
              <TranslatePanel
                sourceText={viewNote.content}
                onAddToNote={t=>{setNote(p=>({...p,content:t}));setViewNote(null);notify('success','Translation loaded in editor!');}}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
